    ("b2c_case_synthetic_05_t095", "05", "Заголовок\nНапиши запрос для анализа поведения пользователей\nДополнительно", "sql", "B", {"system": "напиши запрос", "user": "поведение пользователей"}, 0),
    ("b2c_case_synthetic_05_t096", "05", "Заголовок\nСоздай автотест для проверки безопасности формы\nДополнительно", "java", "A", {"system": "создай автотест", "user": "безопасность форма"}, 1),
    ("b2c_case_synthetic_02_t097", "02", "Напиши функцию для работы с API внешнего сервиса", "python", "B", {"system": "напиши функцию", "user": "api интеграция"}, 0),
    ("b2c_case_synthetic_02_t098", "02", "Создай дашборд для мониторинга метрик системы", "sql", "A", {"system": "создай дашборд", "user": "мониторинг метрики"}, 1),
